from autogen_agentchat.messages import (
    TextMessage, ToolCallMessage, ToolCallResultMessage, StopMessage,
)

result = await team.run(task="Search for the capital of Japan and report it.")

for msg in result.messages:
    if isinstance(msg, TextMessage):
        print(f"[text:{msg.source}] {msg.content[:80]}")
    elif isinstance(msg, ToolCallMessage):
        for call in msg.content:
            print(f"[tool_call:{msg.source}] {call.name}({call.arguments})")
    elif isinstance(msg, ToolCallResultMessage):
        for res in msg.content:
            print(f"[tool_result] {res.content[:60]}")
    elif isinstance(msg, StopMessage):
        print(f"[stop] {msg.content}")
